import { useState, useEffect } from 'react'
import axios from 'axios'
import './App.css'

const API = 'http://localhost:5000/api/tasks'

function App() {
  const [tasks, setTasks] = useState([])
  const [filter, setFilter] = useState('all')
  const [showForm, setShowForm] = useState(false)
  const [editTask, setEditTask] = useState(null)
  const [form, setForm] = useState({
    title: '',
    description: '',
    priority: 'medium',
    deadline: ''
  })

  // Load tasks when page opens
  useEffect(() => {
    fetchTasks()
  }, [filter])

  // Fetch tasks from API
  const fetchTasks = async () => {
    try {
      const url = filter === 'all' ? API : `${API}?status=${filter}`
      const res = await axios.get(url)
      setTasks(res.data)
    } catch (error) {
      console.error('Error fetching tasks:', error)
    }
  }

  // Handle form input changes
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value })
  }

  // Submit form (create or update)
  const handleSubmit = async (e) => {
    e.preventDefault()
    try {
      if (editTask) {
        await axios.put(`${API}/${editTask._id}`, form)
      } else {
        await axios.post(API, form)
      }
      setForm({ title: '', description: '', priority: 'medium', deadline: '' })
      setShowForm(false)
      setEditTask(null)
      fetchTasks()
    } catch (error) {
      alert(error.response?.data?.error || 'Something went wrong')
    }
  }

  // Complete task
  const handleComplete = async (id) => {
    try {
      await axios.patch(`${API}/${id}/complete`)
      fetchTasks()
    } catch (error) {
      console.error('Error completing task:', error)
    }
  }

  // Delete task
  const handleDelete = async (id) => {
    if (window.confirm('Are you sure?')) {
      try {
        await axios.delete(`${API}/${id}`)
        fetchTasks()
      } catch (error) {
        console.error('Error deleting task:', error)
      }
    }
  }

  // Open edit form
  const handleEdit = (task) => {
    setEditTask(task)
    setForm({
      title: task.title,
      description: task.description,
      priority: task.priority,
      deadline: task.deadline ? task.deadline.split('T')[0] : ''
    })
    setShowForm(true)
  }

  // Stats
  const total = tasks.length
  const completed = tasks.filter(t => t.completed).length
  const pending = total - completed

  return (
    <div className="app">
      {/* Header */}
      <div className="header">
        <div>
          <h1>📚 Task Tracker</h1>
          <p>Manage your daily learning tasks</p>
        </div>
        <button className="add-btn" onClick={() => { setShowForm(true); setEditTask(null); setForm({ title: '', description: '', priority: 'medium', deadline: '' }) }}>
          ➕ Add Task
        </button>
      </div>

      {/* Stats */}
      <div className="stats">
        <div className="stat-card">
          <div className="stat-number">{total}</div>
          <div className="stat-label">Total</div>
        </div>
        <div className="stat-card">
          <div className="stat-number">{pending}</div>
          <div className="stat-label">Pending</div>
        </div>
        <div className="stat-card">
          <div className="stat-number">{completed}</div>
          <div className="stat-label">Completed</div>
        </div>
      </div>

      {/* Filters */}
      <div className="filters">
        {['all', 'pending', 'completed'].map(f => (
          <button
            key={f}
            className={`filter-btn ${filter === f ? 'active' : ''}`}
            onClick={() => setFilter(f)}
          >
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      {/* Modal Form */}
      {showForm && (
        <div className="modal-overlay" onClick={() => setShowForm(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editTask ? '✏️ Edit Task' : '➕ Add New Task'}</h2>
              <button className="close-btn" onClick={() => setShowForm(false)}>✕</button>
            </div>

            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Title *</label>
                <input
                  type="text"
                  name="title"
                  value={form.title}
                  onChange={handleChange}
                  placeholder="e.g. Complete React Tutorial"
                  required
                />
              </div>

              <div className="form-group">
                <label>Description</label>
                <textarea
                  name="description"
                  value={form.description}
                  onChange={handleChange}
                  placeholder="Add details..."
                />
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Priority</label>
                  <select name="priority" value={form.priority} onChange={handleChange}>
                    <option value="low">🟢 Low</option>
                    <option value="medium">🟡 Medium</option>
                    <option value="high">🔴 High</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>Deadline</label>
                  <input
                    type="date"
                    name="deadline"
                    value={form.deadline}
                    onChange={handleChange}
                    min={new Date().toISOString().split('T')[0]}
                  />
                </div>
              </div>

              <button type="submit" className="submit-btn">
                {editTask ? 'Save Changes' : 'Add Task'}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Task List */}
      <div className="task-list">
        {tasks.length === 0 ? (
          <div className="empty">
            <p>🎯 No tasks found! Add your first task.</p>
          </div>
        ) : (
          tasks.map(task => (
            <div key={task._id} className={`task-card ${task.completed ? 'completed' : task.priority}`}>
              <div className="task-left">
                <div className={`priority-dot ${task.priority}`}></div>
                <div>
                  <div className={`task-title ${task.completed ? 'done' : ''}`}>{task.title}</div>
                  {task.description && <div className="task-desc">{task.description}</div>}
                  <div className="task-meta">
                    <span className={`badge badge-${task.priority}`}>{task.priority}</span>
                    <span className={`badge ${task.completed ? 'badge-done' : 'badge-pending'}`}>
                      {task.completed ? '✓ Done' : 'Pending'}
                    </span>
                    {task.deadline && (
                      <span className="deadline">
                        📅 {new Date(task.deadline).toLocaleDateString('en-IN')}
                      </span>
                    )}
                  </div>
                </div>
              </div>
              <div className="task-actions">
                {!task.completed && (
                  <>
                    <button className="btn-complete" onClick={() => handleComplete(task._id)}>✓</button>
                    <button className="btn-edit" onClick={() => handleEdit(task)}>✏️</button>
                  </>
                )}
                <button className="btn-delete" onClick={() => handleDelete(task._id)}>🗑</button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  )
}

export default App
